import React, { useState, useEffect } from 'react';
import './CommandeForm.css';

const CommandeForm = ({ selectedCommande, onSuccess }) => {
  const [clients, setClients] = useState([]);
  const [articles, setArticles] = useState([]);

  const [formData, setFormData] = useState({
    codeCli: '',
    codeArt: '',
    dateCom: '',
    QteCom: 1
  });

  useEffect(() => {
    fetchClients();
    fetchArticles();
  }, []);

  useEffect(() => {
    if (selectedCommande) {
      setFormData({
        codeCli: selectedCommande.codeCli,
        codeArt: selectedCommande.codeArt,
        dateCom: selectedCommande.dateCom?.split('T')[0],
        QteCom: selectedCommande.QteCom
      });
    } else {
      resetForm();
    }
  }, [selectedCommande]);

  const fetchClients = async () => {
    try {
      const res = await fetch('http://localhost:3001/clients');
      const data = await res.json();
      setClients(data);
    } catch (err) {
      console.error("Erreur chargement clients :", err);
    }
  };

  const fetchArticles = async () => {
    try {
      const res = await fetch('http://localhost:3001/articles');
      const data = await res.json();
      setArticles(data);
    } catch (err) {
      console.error("Erreur chargement articles :", err);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const resetForm = () => {
    setFormData({
      codeCli: '',
      codeArt: '',
      dateCom: '',
      QteCom: 1
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const method = selectedCommande ? 'PUT' : 'POST';
    const url = selectedCommande
      ? `http://localhost:3001/commandes/${selectedCommande.codeCom}`
      : 'http://localhost:3001/commandes';

    try {
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });
      if (!res.ok) throw new Error(`Erreur ${res.status}`);
      if (!selectedCommande) resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      alert(err.message);
    }
  };

  const handleDelete = async () => {
    if (!selectedCommande) return;
    if (!window.confirm('Supprimer cette commande ?')) return;

    try {
      const res = await fetch(`http://localhost:3001/commandes/${selectedCommande.codeCom}`, {
        method: 'DELETE'
      });

      if (!res.ok) throw new Error(`Erreur ${res.status}`);
      resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      alert(err.message);
    }
  };

  return (
    <form className="commande-form" onSubmit={handleSubmit}>
      <select
        name="codeCli"
        value={formData.codeCli}
        onChange={handleChange}
        required
      >
        <option value="">-- Sélectionner un client --</option>
        {clients.map(cli => (
          <option key={cli.codeCli} value={cli.codeCli}>
            {cli.nomCli} {cli.prenomCli}
          </option>
        ))}
      </select>

      <select
        name="codeArt"
        value={formData.codeArt}
        onChange={handleChange}
        required
      >
        <option value="">-- Sélectionner un article --</option>
        {articles.map(art => (
          <option key={art.codeArt} value={art.codeArt}>
            {art.nomArt}
          </option>
        ))}
      </select>

      <input
        type="date"
        name="dateCom"
        value={formData.dateCom}
        onChange={handleChange}
        required
      />

      <input
        type="number"
        name="QteCom"
        placeholder="Quantité"
        min="1"
        value={formData.QteCom}
        onChange={handleChange}
        required
      />

      <button type="submit">
        {selectedCommande ? 'Modifier' : 'Ajouter'}
      </button>

      {selectedCommande && (
        <button
          type="button"
          onClick={handleDelete}
          style={{ backgroundColor: '#dc3545', marginTop: '10px' }}
        >
          Supprimer
        </button>
      )}
    </form>
  );
};

export default CommandeForm;
